/**
 * MMS Logging Configuration
 *
 * Structured logging with Pino for consistent log format across all services.
 * Features:
 * - JSON format in production
 * - Pretty print in development
 * - Sensitive field redaction
 * - Request ID propagation
 * - OpenTelemetry trace context
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import pino, { type Logger, type LoggerOptions } from 'pino';

const isDevelopment = process.env['NODE_ENV'] === 'development';

/**
 * Fields to redact from logs (prevents PII/secrets leakage)
 */
const REDACT_PATHS = [
  'password',
  'passwordHash',
  'password_hash',
  'token',
  'accessToken',
  'refreshToken',
  'apiKey',
  'api_key',
  'authorization',
  'cookie',
  'creditCard',
  'ssn',
  '*.password',
  '*.token',
  '*.apiKey',
  'req.headers.authorization',
  'req.headers.cookie',
];

/**
 * Base logger configuration
 */
const baseOptions: LoggerOptions = {
  level: process.env['LOG_LEVEL'] ?? (isDevelopment ? 'debug' : 'info'),
  redact: {
    paths: REDACT_PATHS,
    censor: '[REDACTED]',
  },
  formatters: {
    level: (label) => ({ level: label }),
    bindings: (bindings) => ({
      pid: bindings.pid,
      host: bindings.hostname,
      service: process.env['SERVICE_NAME'] ?? 'mms',
    }),
  },
  timestamp: pino.stdTimeFunctions.isoTime,
  base: {
    env: process.env['NODE_ENV'] ?? 'development',
  },
};

/**
 * Development transport (pretty print)
 */
const developmentTransport = {
  target: 'pino-pretty',
  options: {
    colorize: true,
    translateTime: 'HH:MM:ss.l',
    ignore: 'pid,hostname',
    singleLine: false,
  },
};

/**
 * Create the root logger instance
 */
function createLogger(): Logger {
  if (isDevelopment) {
    return pino({
      ...baseOptions,
      transport: developmentTransport,
    });
  }

  return pino(baseOptions);
}

/**
 * Root logger instance
 */
export const logger = createLogger();

/**
 * Create a child logger with additional context
 * Use for service-specific or request-specific logging
 */
export function createChildLogger(context: Record<string, unknown>): Logger {
  return logger.child(context);
}

/**
 * Create a request-scoped logger with trace context
 */
export function createRequestLogger(requestId: string, traceId?: string): Logger {
  return logger.child({
    requestId,
    ...(traceId && { traceId }),
  });
}

/**
 * Log level type
 */
export type LogLevel = 'trace' | 'debug' | 'info' | 'warn' | 'error' | 'fatal';

/**
 * Structured error logging helper
 */
export function logError(
  log: Logger,
  error: Error,
  context?: Record<string, unknown>
): void {
  const errObj: Record<string, unknown> = {
    message: error.message,
    name: error.name,
    stack: error.stack,
  };
  if (error.cause) {
    errObj.cause = error.cause;
  }
  log.error(
    {
      err: errObj,
      ...context,
    },
    error.message
  );
}

/**
 * Performance timing helper
 */
export function logTiming(
  log: Logger,
  operation: string,
  durationMs: number,
  context?: Record<string, unknown>
): void {
  const level: LogLevel = durationMs > 1000 ? 'warn' : 'info';
  log[level](
    {
      operation,
      durationMs,
      ...context,
    },
    `${operation} completed in ${durationMs}ms`
  );
}

export default logger;

/**
 * MMS Prometheus Metrics
 *
 * Application metrics for monitoring and alerting.
 * Exposed via /metrics endpoint for Prometheus scraping.
 *
 * Metric types:
 * - Counter: Monotonically increasing values (requests, errors)
 * - Gauge: Point-in-time values (active jobs, queue depth)
 * - Histogram: Distribution of values (request duration, solve time)
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import { Registry, Counter, Gauge, Histogram, collectDefaultMetrics } from 'prom-client';

// =============================================================================
// Registry Setup
// =============================================================================

export const registry = new Registry();

// Add default Node.js metrics (CPU, memory, event loop, etc.)
collectDefaultMetrics({
  register: registry,
  prefix: 'mms_',
});

// =============================================================================
// HTTP Metrics
// =============================================================================

export const httpRequestsTotal = new Counter({
  name: 'mms_http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'path', 'status'] as const,
  registers: [registry],
});

export const httpRequestDuration = new Histogram({
  name: 'mms_http_request_duration_seconds',
  help: 'HTTP request duration in seconds',
  labelNames: ['method', 'path', 'status'] as const,
  buckets: [0.01, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10],
  registers: [registry],
});

export const httpRequestsInFlight = new Gauge({
  name: 'mms_http_requests_in_flight',
  help: 'Number of HTTP requests currently being processed',
  labelNames: ['method'] as const,
  registers: [registry],
});

// =============================================================================
// PM Scheduling Metrics
// =============================================================================

export const pmScheduledTotal = new Counter({
  name: 'mms_pm_scheduled_total',
  help: 'Total number of PM events scheduled',
  labelNames: ['pm_code', 'fleet_id', 'status'] as const,
  registers: [registry],
});

export const pmComplianceWindowDays = new Histogram({
  name: 'mms_pm_compliance_window_days',
  help: 'Days between PM scheduling and compliance window end',
  labelNames: ['pm_code'] as const,
  buckets: [-14, -7, 0, 7, 14, 30, 60, 90],
  registers: [registry],
});

export const pmDeferredTotal = new Counter({
  name: 'mms_pm_deferred_total',
  help: 'Total number of PM events deferred',
  labelNames: ['pm_code', 'reason'] as const,
  registers: [registry],
});

// =============================================================================
// Optimizer Metrics
// =============================================================================

export const optimizerSolveSeconds = new Histogram({
  name: 'mms_optimizer_solve_seconds',
  help: 'Optimizer solve time in seconds',
  labelNames: ['solver_type', 'status'] as const,
  buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120],
  registers: [registry],
});

export const optimizerRunsTotal = new Counter({
  name: 'mms_optimizer_runs_total',
  help: 'Total number of optimizer runs',
  labelNames: ['solver_type', 'status'] as const,
  registers: [registry],
});

export const optimizerObjectiveValue = new Gauge({
  name: 'mms_optimizer_objective_value',
  help: 'Latest optimizer objective value',
  labelNames: ['solver_type'] as const,
  registers: [registry],
});

export const optimizerFallbacksTotal = new Counter({
  name: 'mms_optimizer_fallbacks_total',
  help: 'Number of times fallback solver was used',
  labelNames: ['reason'] as const,
  registers: [registry],
});

// =============================================================================
// Fleet Metrics
// =============================================================================

export const fleetMileageKm = new Gauge({
  name: 'mms_fleet_mileage_km',
  help: 'Current cumulative mileage per train',
  labelNames: ['train_id', 'fleet_id'] as const,
  registers: [registry],
});

export const fleetTrainStatus = new Gauge({
  name: 'mms_fleet_train_status',
  help: 'Train fitness status (1=FIT, 0.5=RESTRICTED, 0=GROUNDED)',
  labelNames: ['train_id', 'fleet_id', 'status'] as const,
  registers: [registry],
});

export const fleetAvailableTrains = new Gauge({
  name: 'mms_fleet_available_trains',
  help: 'Number of trains available for service',
  labelNames: ['fleet_id'] as const,
  registers: [registry],
});

// =============================================================================
// Drift Metrics
// =============================================================================

export const driftTrainsRequiringReplan = new Gauge({
  name: 'mms_drift_trains_requiring_replan',
  help: 'Number of trains requiring schedule replan due to drift',
  labelNames: ['baseline_id'] as const,
  registers: [registry],
});

export const driftMileagePercent = new Gauge({
  name: 'mms_drift_mileage_percent',
  help: 'Mileage drift percentage per train',
  labelNames: ['train_id', 'baseline_id'] as const,
  registers: [registry],
});

export const driftAnalysisTotal = new Counter({
  name: 'mms_drift_analysis_total',
  help: 'Total number of drift analyses performed',
  labelNames: ['result'] as const,
  registers: [registry],
});

// =============================================================================
// Queue Metrics
// =============================================================================

export const queueJobsTotal = new Counter({
  name: 'mms_queue_jobs_total',
  help: 'Total number of queue jobs processed',
  labelNames: ['queue', 'status'] as const,
  registers: [registry],
});

export const queueJobDuration = new Histogram({
  name: 'mms_queue_job_duration_seconds',
  help: 'Queue job processing duration in seconds',
  labelNames: ['queue', 'job_name'] as const,
  buckets: [0.1, 1, 5, 10, 30, 60, 300, 600],
  registers: [registry],
});

export const queueDepth = new Gauge({
  name: 'mms_queue_depth',
  help: 'Number of jobs waiting in queue',
  labelNames: ['queue', 'state'] as const,
  registers: [registry],
});

// =============================================================================
// Ingestion Metrics
// =============================================================================

export const ingestionFilesTotal = new Counter({
  name: 'mms_ingestion_files_total',
  help: 'Total number of files processed',
  labelNames: ['status'] as const,
  registers: [registry],
});

export const ingestionRowsTotal = new Counter({
  name: 'mms_ingestion_rows_total',
  help: 'Total number of rows processed',
  labelNames: ['status'] as const,
  registers: [registry],
});

export const ingestionAnomaliesTotal = new Counter({
  name: 'mms_ingestion_anomalies_total',
  help: 'Total number of anomalies detected',
  labelNames: ['type'] as const,
  registers: [registry],
});

// =============================================================================
// Man-hour Metrics
// =============================================================================

export const manhourUtilizationPercent = new Gauge({
  name: 'mms_manhour_utilization_percent',
  help: 'Man-hour utilization percentage per depot',
  labelNames: ['depot_id', 'period'] as const,
  registers: [registry],
});

export const manhourOverloadedPeriods = new Gauge({
  name: 'mms_manhour_overloaded_periods',
  help: 'Number of overloaded periods per depot',
  labelNames: ['depot_id'] as const,
  registers: [registry],
});

export const manhourAdjustmentsTotal = new Counter({
  name: 'mms_manhour_adjustments_total',
  help: 'Total number of man-hour adjustments made',
  labelNames: ['depot_id', 'strategy', 'status'] as const,
  registers: [registry],
});

// =============================================================================
// Notification Metrics
// =============================================================================

export const notificationsQueued = new Counter({
  name: 'mms_notifications_queued_total',
  help: 'Total number of notifications queued',
  labelNames: ['type', 'severity'] as const,
  registers: [registry],
});

export const notificationsSent = new Counter({
  name: 'mms_notifications_sent_total',
  help: 'Total number of notifications sent',
  labelNames: ['template', 'status'] as const,
  registers: [registry],
});

export const notificationsDigested = new Counter({
  name: 'mms_notifications_digested_total',
  help: 'Total number of notifications added to digest batches',
  labelNames: ['digest_mode'] as const,
  registers: [registry],
});

export const digestBatchesProcessed = new Counter({
  name: 'mms_digest_batches_processed_total',
  help: 'Total number of digest batches processed',
  labelNames: ['status'] as const,
  registers: [registry],
});

export const notificationMetrics = {
  notificationsQueued,
  notificationsSent,
  notificationsDigested,
  digestBatchesProcessed,
};

// =============================================================================
// Database Metrics
// =============================================================================

export const dbQueryDuration = new Histogram({
  name: 'mms_db_query_duration_seconds',
  help: 'Database query duration in seconds',
  labelNames: ['operation', 'table'] as const,
  buckets: [0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1, 5],
  registers: [registry],
});

export const dbConnectionPoolSize = new Gauge({
  name: 'mms_db_connection_pool_size',
  help: 'Database connection pool size',
  labelNames: ['state'] as const,
  registers: [registry],
});

export const dbErrorsTotal = new Counter({
  name: 'mms_db_errors_total',
  help: 'Total number of database errors',
  labelNames: ['operation', 'error_code'] as const,
  registers: [registry],
});

// =============================================================================
// Utility Functions
// =============================================================================

/**
 * Get metrics output for Prometheus scraping
 */
export async function getMetrics(): Promise<string> {
  return registry.metrics();
}

/**
 * Get content type for metrics response
 */
export function getMetricsContentType(): string {
  return registry.contentType;
}

/**
 * Reset all metrics (useful for testing)
 */
export function resetMetrics(): void {
  registry.resetMetrics();
}

/**
 * HTTP middleware helper - measure request duration
 */
export function measureHttpRequest(
  method: string,
  path: string,
  status: number,
  durationMs: number
): void {
  const labels = { method, path, status: String(status) };
  httpRequestsTotal.inc(labels);
  httpRequestDuration.observe(labels, durationMs / 1000);
}

/**
 * Queue job helper - record job completion
 */
export function recordQueueJob(
  queue: string,
  jobName: string,
  status: 'completed' | 'failed',
  durationMs: number
): void {
  queueJobsTotal.inc({ queue, status });
  queueJobDuration.observe({ queue, job_name: jobName }, durationMs / 1000);
}

/**
 * Optimizer helper - record solve completion
 */
export function recordOptimizerRun(
  solverType: 'cpsat' | 'fallback',
  status: 'optimal' | 'feasible' | 'infeasible' | 'timeout' | 'error',
  durationMs: number,
  objective?: number
): void {
  optimizerRunsTotal.inc({ solver_type: solverType, status });
  optimizerSolveSeconds.observe({ solver_type: solverType, status }, durationMs / 1000);
  if (objective !== undefined) {
    optimizerObjectiveValue.set({ solver_type: solverType }, objective);
  }
}

// =============================================================================
// Worker Metrics
// =============================================================================

/**
 * Worker metrics object for worker infrastructure
 */
export const workerMetrics = {
  queueJobStarted: new Counter({
    name: 'mms_worker_job_started_total',
    help: 'Total number of jobs started by workers',
    labelNames: ['queue'] as const,
    registers: [registry],
  }),
  queueJobCompleted: new Counter({
    name: 'mms_worker_job_completed_total',
    help: 'Total number of jobs completed successfully by workers',
    labelNames: ['queue'] as const,
    registers: [registry],
  }),
  queueJobFailed: new Counter({
    name: 'mms_worker_job_failed_total',
    help: 'Total number of jobs failed by workers',
    labelNames: ['queue'] as const,
    registers: [registry],
  }),
  queueJobDuration: new Histogram({
    name: 'mms_worker_job_duration_seconds',
    help: 'Worker job processing duration in seconds',
    labelNames: ['queue'] as const,
    buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120, 300, 600],
    registers: [registry],
  }),
};

// =============================================================================
// Ingestion Helpers
// =============================================================================

/**
 * Ingestion metrics object for easy access
 */
export const ingestionMetrics = {
  filesReceived: new Counter({
    name: 'mms_ingestion_files_received_total',
    help: 'Total number of files received for ingestion',
    registers: [registry],
  }),
  recordsProcessed: new Counter({
    name: 'mms_ingestion_records_processed_total',
    help: 'Total number of records processed',
    registers: [registry],
  }),
  processingDuration: new Histogram({
    name: 'mms_ingestion_processing_duration_seconds',
    help: 'Ingestion processing duration in seconds',
    labelNames: ['status'] as const,
    buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120, 300],
    registers: [registry],
  }),
};

/**
 * Record ingestion completion
 */
export function recordIngestionComplete(
  status: 'SUCCESS' | 'PARTIAL' | 'FAILED',
  durationMs: number
): void {
  ingestionFilesTotal.inc({ status: status.toLowerCase() });
  ingestionMetrics.processingDuration.observe({ status: status.toLowerCase() }, durationMs / 1000);
}

/**
 * Record ingestion anomaly
 */
export function recordIngestionAnomaly(type: string): void {
  ingestionAnomaliesTotal.inc({ type });
}

// =============================================================================
// Optimizer Metrics
// =============================================================================

/**
 * Optimizer metrics object for optimizer infrastructure
 */
export const optimizerMetrics = {
  optimizerSolveSeconds: new Histogram({
    name: 'mms_optimizer_worker_solve_seconds',
    help: 'Optimizer solve duration in seconds',
    labelNames: ['solver_type', 'status'] as const,
    buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120, 300],
    registers: [registry],
  }),
  trainsAssigned: new Gauge({
    name: 'mms_optimizer_trains_assigned',
    help: 'Number of trains assigned in last optimization',
    labelNames: ['fleet_id'] as const,
    registers: [registry],
  }),
  trainsUnassigned: new Gauge({
    name: 'mms_optimizer_trains_unassigned',
    help: 'Number of trains not assigned in last optimization',
    labelNames: ['fleet_id'] as const,
    registers: [registry],
  }),
  materialBlocks: new Counter({
    name: 'mms_optimizer_material_blocks_total',
    help: 'Total number of material constraint blocks',
    labelNames: ['depot_id'] as const,
    registers: [registry],
  }),
};

// =============================================================================
// Costing Metrics
// =============================================================================

/**
 * Costing metrics object for TCO and variance tracking
 */
export const costingMetrics = {
  pmCostCalculated: new Counter({
    name: 'mms_costing_pm_cost_calculated_total',
    help: 'Total number of PM costs calculated',
    labelNames: ['pm_type', 'depot_id'] as const,
    registers: [registry],
  }),
  tcoProjected: new Histogram({
    name: 'mms_costing_tco_npv',
    help: 'TCO NPV projection value',
    buckets: [100000, 500000, 1000000, 5000000, 10000000, 50000000, 100000000],
    registers: [registry],
  }),
  varianceCalculated: new Histogram({
    name: 'mms_costing_variance_percent',
    help: 'Cost variance percentage calculated',
    labelNames: ['fiscal_year', 'depot_id', 'status'] as const,
    buckets: [-50, -20, -10, -5, 0, 5, 10, 20, 50],
    registers: [registry],
  }),
};

// =============================================================================
// Maximo Integration Metrics
// =============================================================================

/**
 * Maximo integration metrics for sync operations and polling fallback
 *
 * @see specs/007-integration.md Section 7.11.2
 */
export const maximoMetrics = {
  // Sync operations
  syncRequestsTotal: new Counter({
    name: 'mms_maximo_sync_requests_total',
    help: 'Total number of Maximo sync requests',
    labelNames: ['operation', 'status'] as const,
    registers: [registry],
  }),
  syncDuration: new Histogram({
    name: 'mms_maximo_sync_duration_seconds',
    help: 'Maximo sync operation duration in seconds',
    labelNames: ['operation'] as const,
    buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120],
    registers: [registry],
  }),
  syncRecordsProcessed: new Counter({
    name: 'mms_maximo_sync_records_processed_total',
    help: 'Total number of records processed during sync',
    labelNames: ['operation', 'result'] as const,
    registers: [registry],
  }),

  // Webhook metrics
  webhooksReceived: new Counter({
    name: 'mms_maximo_webhooks_received_total',
    help: 'Total number of webhooks received from Maximo',
    labelNames: ['event_type', 'status'] as const,
    registers: [registry],
  }),
  webhookProcessingDuration: new Histogram({
    name: 'mms_maximo_webhook_processing_duration_seconds',
    help: 'Webhook processing duration in seconds',
    labelNames: ['event_type'] as const,
    buckets: [0.01, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5],
    registers: [registry],
  }),
  webhookLastReceivedAt: new Gauge({
    name: 'mms_maximo_webhook_last_received_timestamp',
    help: 'Timestamp of last webhook received (Unix epoch)',
    labelNames: ['depot_id'] as const,
    registers: [registry],
  }),

  // Polling fallback metrics
  pollingTriggered: new Counter({
    name: 'mms_maximo_polling_triggered_total',
    help: 'Total number of polling jobs triggered',
    labelNames: ['trigger_reason'] as const,
    registers: [registry],
  }),
  pollingRecordsFound: new Counter({
    name: 'mms_maximo_polling_records_found_total',
    help: 'Total number of records found during polling',
    registers: [registry],
  }),
  pollingDuration: new Histogram({
    name: 'mms_maximo_polling_duration_seconds',
    help: 'Polling operation duration in seconds',
    buckets: [0.5, 1, 5, 10, 30, 60, 120],
    registers: [registry],
  }),
  pollingFallbackActive: new Gauge({
    name: 'mms_maximo_polling_fallback_active',
    help: 'Whether polling fallback is currently active (1=active, 0=inactive)',
    labelNames: ['depot_id'] as const,
    registers: [registry],
  }),

  // Sync mode metrics
  syncMode: new Gauge({
    name: 'mms_maximo_sync_mode',
    help: 'Current sync mode (0=webhook, 1=polling, 2=hybrid)',
    labelNames: ['depot_id'] as const,
    registers: [registry],
  }),

  // Deduplication metrics
  duplicatesPrevented: new Counter({
    name: 'mms_maximo_duplicates_prevented_total',
    help: 'Total number of duplicate updates prevented',
    registers: [registry],
  }),

  // Circuit breaker metrics
  circuitBreakerState: new Gauge({
    name: 'mms_maximo_circuit_breaker_state',
    help: 'Circuit breaker state (0=closed, 1=open, 2=half-open)',
    registers: [registry],
  }),
  circuitBreakerTrips: new Counter({
    name: 'mms_maximo_circuit_breaker_trips_total',
    help: 'Total number of circuit breaker trips',
    registers: [registry],
  }),

  // Conflict metrics
  conflictsDetected: new Counter({
    name: 'mms_maximo_conflicts_detected_total',
    help: 'Total number of sync conflicts detected',
    registers: [registry],
  }),
  conflictsResolved: new Counter({
    name: 'mms_maximo_conflicts_resolved_total',
    help: 'Total number of sync conflicts resolved',
    labelNames: ['resolution'] as const,
    registers: [registry],
  }),

  // Shadow record metrics
  shadowRecordsPending: new Gauge({
    name: 'mms_maximo_shadow_records_pending',
    help: 'Number of shadow records pending sync',
    registers: [registry],
  }),
  shadowRecordsConflict: new Gauge({
    name: 'mms_maximo_shadow_records_conflict',
    help: 'Number of shadow records in conflict state',
    registers: [registry],
  }),
  shadowRecordsError: new Gauge({
    name: 'mms_maximo_shadow_records_error',
    help: 'Number of shadow records in error state',
    registers: [registry],
  }),
};

/**
 * Record Maximo sync operation
 */
export function recordMaximoSync(
  operation: 'push' | 'pull' | 'full' | 'polling',
  status: 'success' | 'failure' | 'partial',
  durationMs: number,
  recordsProcessed: number,
  recordsUpdated: number
): void {
  maximoMetrics.syncRequestsTotal.inc({ operation, status });
  maximoMetrics.syncDuration.observe({ operation }, durationMs / 1000);
  maximoMetrics.syncRecordsProcessed.inc({ operation, result: 'processed' }, recordsProcessed);
  maximoMetrics.syncRecordsProcessed.inc({ operation, result: 'updated' }, recordsUpdated);
}

/**
 * Record webhook received
 */
export function recordMaximoWebhook(
  eventType: string,
  status: 'success' | 'failure',
  durationMs: number,
  depotId?: string
): void {
  maximoMetrics.webhooksReceived.inc({ event_type: eventType, status });
  maximoMetrics.webhookProcessingDuration.observe({ event_type: eventType }, durationMs / 1000);
  if (status === 'success') {
    maximoMetrics.webhookLastReceivedAt.set({ depot_id: depotId ?? 'global' }, Date.now() / 1000);
  }
}

/**
 * Record polling fallback activation
 */
export function recordPollingFallbackActivation(reason: 'webhook_timeout' | 'manual' | 'circuit_breaker'): void {
  maximoMetrics.pollingTriggered.inc({ trigger_reason: reason });
}

/**
 * Update sync mode metric
 */
export function updateSyncModeMetric(depotId: string, mode: 'WEBHOOK' | 'POLLING' | 'HYBRID'): void {
  const modeValue = mode === 'WEBHOOK' ? 0 : mode === 'POLLING' ? 1 : 2;
  maximoMetrics.syncMode.set({ depot_id: depotId }, modeValue);
  maximoMetrics.pollingFallbackActive.set({ depot_id: depotId }, mode !== 'WEBHOOK' ? 1 : 0);
}

// =============================================================================
// Rate Limiting Metrics
// =============================================================================

/**
 * Rate limiting metrics for monitoring and alerting
 *
 * @see specs/005-api.md - Rate Limiting: 100 requests/minute per user
 */
export const rateLimitMetrics = {
  /**
   * Total rate limit checks performed
   */
  rateLimitChecks: new Counter({
    name: 'mms_rate_limit_checks_total',
    help: 'Total number of rate limit checks performed',
    labelNames: ['identifier_type', 'result'] as const,
    registers: [registry],
  }),

  /**
   * Rate limit exceeded events
   */
  rateLimitExceeded: new Counter({
    name: 'mms_rate_limit_exceeded_total',
    help: 'Total number of requests rejected due to rate limiting',
    labelNames: ['identifier_type'] as const,
    registers: [registry],
  }),

  /**
   * Current rate limit window usage per identifier
   */
  rateLimitUsage: new Gauge({
    name: 'mms_rate_limit_usage',
    help: 'Current rate limit usage percentage',
    labelNames: ['identifier_type'] as const,
    registers: [registry],
  }),
};

/**
 * Record rate limit check result
 */
export function recordRateLimitCheck(
  identifierType: 'user' | 'ip',
  result: 'allowed' | 'exceeded'
): void {
  rateLimitMetrics.rateLimitChecks.inc({ identifier_type: identifierType, result });
  if (result === 'exceeded') {
    rateLimitMetrics.rateLimitExceeded.inc({ identifier_type: identifierType });
  }
}

