/**
 * MMS API Server Entry Point
 *
 * Starts the Hono server using Bun runtime.
 * Use this file to start the API server standalone.
 *
 * Usage: bun run src/api/server.ts
 *
 * Environment Variables:
 * - PORT: Server port (default: 3000)
 * - HOST: Server host (default: 0.0.0.0)
 * - NODE_ENV: Environment (development, production, test)
 */

import { getApp } from './index';
import { logger } from '../lib/logging/logger';

const PORT = Number(process.env.PORT) || 3000;
const HOST = process.env.HOST || '0.0.0.0';

const app = getApp();

logger.info({ port: PORT, host: HOST, env: process.env.NODE_ENV }, 'Starting MMS API server');

export default {
  port: PORT,
  hostname: HOST,
  fetch: app.fetch,
};

