/**
 * MMS Shared Library
 *
 * Central exports for all shared utilities, types, and configurations.
 * Note: Schemas are exported under 'schemas' namespace to avoid collisions with DB types.
 */

// Database
export * from './db/connection';
export * from './db/schema';

// Redis
export * from './redis/connection';

// Logging
export * from './logging/logger';

// Errors
export * from './errors';

// Tracing (OpenTelemetry)
export * from './tracing';

// Base Service Infrastructure
export * from './services';

// Utilities
export * from './utils/date';
export * from './utils/transaction';
export * from './utils/resilience';

// Queues
export * from './queue';

// Validation Schemas (using @belt/tools) - exported under namespace to avoid conflicts with DB schema types
export * as schemas from './schemas';

// Metrics
export * from './metrics';
